#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    pid_t pid = fork();

    if (pid == -1) {
        // Error handling
        perror("fork");
        return 1;
    } else if (pid == 0) {
        // Child process
        dup2(STDOUT_FILENO, 1); // Redirect child's standard output to the parent's file descriptor
        execlp("your_command", "your_command", (char*)0);
        perror("execlp");
        _exit(1); // Exit the child process
    } else {
        // Parent process
        int status;
        waitpid(pid, &status, 0); // Wait for the child process to finish
    }

    return 0;
}
```

In this example, `fork()` creates a new process, and `dup2()` is used to duplicate the file descriptor connected to the parent's standard output to the child's standard input and standard output. The `execlp()` function is then used to execute a command in the child process.

Remember to replace `"your_command"` with the actual command you want to run. This example assumes you are on a Unix-like system where `fork()` and `exec()` are available.
